    fn eq(&self, other: &Self) -> bool {
        match (self, other) {
            (Self::NonCritical(x), Self::NonCritical(y)) => x == y,
            (Self::Critical(x), Self::Critical(y)) => x == y,
            _ => false,
        }
    }
