///
pub trait EncWis: Sized {
    ///
    fn new(key: &[u8]) -> Result<Self, &'static str>;

    /// (HEAD non enc), (PAYLOAD enc), (TAG) (countr(nonce)), (NONCE)
    fn encrypt(
        &self,
        non_enc_head: &[u8],
        enc_payload: &mut [u8],
        auth_tag: &mut [u8],
        nonce_countr: u64,
        nonce: Option<&[u8]>,
    ) -> Result<(), &'static str>;
    /// (HEAD non enc), (PAYLOAD enc), (TAG) (countr(nonce)), (NONCE)
    fn decrypt(
        &self,
        non_enc_head: &[u8],
        enc_payload: &mut [u8],
        auth_tag: &mut [u8],
        nonce_countr: u64,
        nonce: Option<&[u8]>,
    ) -> Result<StatusDecrypt, &'static str>;
}
